CREATE OR REPLACE FUNCTION public.get_dashboard_metrics(_range_start timestamp with time zone, _range_end timestamp with time zone) RETURNS jsonb LANGUAGE plpgsql STABLE SECURITY DEFINER SET search_path TO 'public' AS $function$ DECLARE result jsonb; v_uid uuid := auth.uid(); BEGIN WITH RECURSIVE downline AS (SELECT v_uid AS id UNION ALL SELECT p.id FROM public.profiles p JOIN downline d ON p.upline_id = d.id), team_ids AS (SELECT id FROM downline), scoped AS (SELECT pol.id, pol.agent_id, pol.annual_premium, pol.status, (pol.agent_id = v_uid) AS is_mine, COALESCE(pol.effective_date::timestamptz, pol.posted_at) AS biz_date FROM public.policies pol WHERE pol.agent_id IN (SELECT id FROM team_ids)), in_range AS (SELECT * FROM scoped WHERE biz_date >= _range_start AND biz_date < _range_end), kpis AS (SELECT COALESCE(SUM(CASE WHEN is_mine THEN annual_premium END),0) AS my_prod, COALESCE(SUM(annual_premium),0) AS team_prod, COUNT(*) FILTER (WHERE is_mine) AS my_policies, COUNT(*) AS team_policies FROM in_range), status_grid AS (SELECT status::text AS status, COUNT(*) AS cnt FROM public.policies WHERE agent_id IN (SELECT id FROM team_ids) GROUP BY status), donut AS (SELECT COUNT(*) FILTER (WHERE status::text='active') AS active_cnt, COUNT(*) FILTER (WHERE status::text='in_review') AS in_review_cnt, COUNT(*) AS total_cnt FROM scoped WHERE biz_date >= now() - interval '30 days'), active_downline AS (SELECT COUNT(*) AS cnt FROM public.profiles WHERE upline_id = v_uid), active_contracts AS (SELECT COUNT(*) AS cnt FROM public.agent_commission_levels WHERE agent_id = v_uid), months AS (SELECT date_trunc('month', now()) - (i || ' months')::interval AS m_start FROM generate_series(0,11) i), trend AS (SELECT to_char(m.m_start,'YYYY-MM-DD') AS month, COALESCE(SUM(CASE WHEN s.is_mine THEN s.annual_premium END),0) AS my_prod, COALESCE(SUM(s.annual_premium),0) AS team_prod, COUNT(*) FILTER (WHERE s.is_mine) AS my_policies, COUNT(s.id) AS team_policies FROM months m LEFT JOIN scoped s ON s.biz_date >= m.m_start AND s.biz_date < m.m_start + interval '1 month' GROUP BY m.m_start ORDER BY m.m_start) SELECT jsonb_build_object('my_prod',(SELECT my_prod FROM kpis),'team_prod',(SELECT team_prod FROM kpis),'my_policies',(SELECT my_policies FROM kpis),'team_policies',(SELECT team_policies FROM kpis),'status_grid', COALESCE((SELECT jsonb_object_agg(status,cnt) FROM status_grid),'{}'::jsonb),'donut', jsonb_build_object('active',(SELECT active_cnt FROM donut),'in_review',(SELECT in_review_cnt FROM donut),'total',(SELECT total_cnt FROM donut)),'active_downline',(SELECT cnt FROM active_downline),'active_contracts',(SELECT cnt FROM active_contracts),'trend', COALESCE((SELECT jsonb_agg(jsonb_build_object('month',month,'my_prod',my_prod,'team_prod',team_prod,'my_policies',my_policies,'team_policies',team_policies)) FROM trend),'[]'::jsonb)) INTO result; RETURN result; END; $function$;